ch\" type=\"button\" :disabled=\"preset.is_loaded\" @click.stop=\"$emit('switch', preset.name)\">\n              切换\n            </button>\n          </td>\n        </tr>\n        <tr v-if=\"!presets.length\">\n          <td colspan=\"5\" class=\"empty\">没有匹配的预设</td>\n        </tr>\n      </tbody>\n    </table>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport type { PresetSummary } from '../types';\n\ndefineProps<{\n  presets: PresetSummary[];\n}>();\n\ndefineEmits<{\n  select: [name: string];\n  switch: [name: string];\n  'toggle-favorite': [name: string, favorite: boolean];\n}>();\n</script>\n\n<style scoped>\n.table-wrap {\n  border: 1px solid rgba(70, 93, 122, 0.7);\n  border-radius: 12px;\n  overflow: auto;\n  background: rgba(8, 13, 24, 0.72);\n}\n\n.table {\n  width: 100%;\n  border-collapse: collapse;\n  min-width: 540px;\n}\n\nth,\ntd {\n  padding: 9px 10px;\n  border-bottom: 1px solid rgba(44, 62, 88, 0.52);\n  text-align: left;\n  color: #d9e8ff;\n  font-size: 12px;\n  vertical-align: middle;\n}\n\nthead th {\n  background: rgba(17, 24, 39, 0.94);\n  color: #9cc4fa;\n  position: sticky;\n  top: 0;\n  z-index: 1;\n}\n\ntbody tr {\n  cursor: pointer;\n}\n\ntbody tr:hover {\n  background: rgba(30, 64, 175, 0.14);\n}\n\ntbody tr.selected {\n  background: rgba(59, 130, 246, 0.18);\n}\n\n.name-cell {\n  display: flex;\n  align-items: center;\n  gap: 6px;\n  min-width: 0;\n}\n\n.name-cell > span {\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.star {\n  border: none;\n  background: transparent;\n  color: #fbbf24;\n  font-size: 16px;\n  cursor: pointer;\n}\n\n.status {\n  color: #93a4be;\n}\n\n.status.loaded {\n  color: #34d399;\n}\n\n.tags-cell {\n  color: #a8c2e7;\n}\n\n.switch {\n  border: 1px solid rgba(86, 114, 156, 0.72);\n  border-radius: 7px;\n  background: #1f2a44;\n  color: #f5f8ff;\n  padding: 4px 9px;\n  cursor: pointer;\n}\n\n.switch:disabled {\n  opacity: 0.45;\n  cursor: default;\n}\n\n.empty {\n  color: #8ba3c7;\n}\n</style>\n"],"sourceRoot":""}]);
