`, "",{"version":3,"sources":["webpack://./src/presets_assistant_build/components/EditModeShell.vue"],"names":[],"mappings":"AAwUA,6BACE,oCAAwC,CACxC,kBAAmB,CACnB,eAAgB,CAChB,yEAAkF,CAClF,YAAa,CACb,qBAAsB,CACtB,YACF,CAEA,0BACE,YAAa,CACb,6BAA8B,CAC9B,QAAS,CACT,kBAAmB,CACnB,iBAAkB,CAClB,4CAAgD,CAChD,cACF,CAEA,uBACE,mBAAoB,CACpB,kBAAmB,CACnB,OAAQ,CACR,aAAc,CACd,cACF,CAEA,4EAGE,sCAA0C,CAC1C,iBAAkB,CAClB,6BAAiC,CACjC,aAAc,CACd,eACF,CAEA,0BACE,mBAAoB,CACpB,OACF,CAEA,0BACE,YAAa,CACb,MAAO,CACP,YAAa,CACb,yCACF,CAEA,8BACE,2CAA+C,CAC/C,YAAa,CACb,YAAa,CACb,qBAAsB,CACtB,OAAQ,CACR,aACF,CAEA,mCACE,YAAa,CACb,6BAA8B,CAC9B,kBAAmB,CACnB,aACF,CAEA,8BACE,oCAAwC,CACxC,iBAAkB,CAClB,8BAAkC,CAClC,aAAc,CACd,eAAgB,CAChB,eAAgB,CAChB,YAAa,CACb,OAAQ,CACR,cACF,CAEA,oCACE,aAAc,CACd,cACF,CAEA,qCACE,oBAAqB,CACrB,gDACF,CAEA,yBACE,YAAa,CACb,aAAc,CACd,YAAa,CACb,YAAa,CACb,QACF,CAEA,wBACE,oCAAwC,CACxC,iBAAkB,CAClB,WAAY,CACZ,8BAAkC,CAClC,YAAa,CACb,OACF,CAEA,2BACE,QAAS,CACT,aAAc,CACd,cACF,CAEA,wBACE,YAAa,CACb,OACF,CAEA,6BACE,aAAc,CACd,cACF,CAEA,sBACE,YAAa,CACb,6BAA8B,CAC9B,OACF,CAEA,2BACE,gBACF,CAEA,wBACE,mBAAoB,CACpB,kBAAmB,CACnB,OAAQ,CACR,aAAc,CACd,cACF,CAEA,sBACE,mBAAoB,CACpB,OAAQ,CACR,cACF,CAEA,wBACE,qCAAyC,CACzC,iBAAkB,CAClB,8BACF,CAEA,gCACE,cAAe,CACf,eAAgB,CAChB,gBAAiB,CACjB,aAAc,CACd,cACF,CAEA,gCACE,YAAa,CACb,OAAQ,CACR,WACF,CAEA,sBACE,sCAA0C,CAC1C,iBAAkB,CAClB,kBAAmB,CACnB,aAAc,CACd,gBAAiB,CACjB,cACF,CAEA,8BACE,kBAAmB,CACnB,oBACF,CAEA,6BACE,kBAAmB,CACnB,oBACF,CAEA,2BACE,gBAAiB,CACjB,cACF,CAEA,+BACE,WAAY,CACZ,cACF,CAEA,wBACE,YAAa,CACb,aAAc,CACd,cACF,CAEA,0BACE,0BACE,yBACF,CAEA,8BACE,iBAAkB,CAClB,4CAAgD,CAChD,gBACF,CAEA,sBACE,yBACF,CACF","sourcesContent":["<template>\n  <section class=\"edit-shell\">\n    <header class=\"toolbar\">\n      <div class=\"mode\">\n        <span>编辑模式</span>\n        <select :value=\"applyMode\" class=\"select\" @change=\"emitApplyMode(($event.target as HTMLSelectElement).value)\">\n          <option value=\"live\">实时模式</option>\n          <option value=\"draft\">草稿模式</option>\n        </select>\n      </div>\n      <div class=\"actions\">\n        <button class=\"btn\" type=\"button\" :disabled=\"!dirty || saving\" @click=\"$emit('discard')\">丢弃改动</button>\n        <button class=\"btn primary\" type=\"button\" :disabled=\"!dirty || saving\" @click=\"$emit('save')\">\n          {{ saving ? '保存中...' : '保存到预设' }}\n        </button>\n      </div>\n    </header>\n\n    <div v-if=\"draftPreset\" class=\"content\">\n      <aside class=\"prompt-list\">\n        <div class=\"prompt-list-head\">\n          <strong>提示词词条</strong>\n          <button class=\"btn mini\" type=\"button\" @click=\"$emit('append-prompt')\">新增</button>\n        </div>\n        <button\n          v-for=\"(prompt, index) in draftPreset.prompts\"\n          :key=\"`${prompt.id}-${index}`\"\n          class=\"prompt-item\"\n          :class=\"{ active: index === selectedPromptIndex }\"\n          type=\"button\"\n          @click=\"$emit('set-selected-prompt-index', index)\"\n        >\n          <span>{{ prompt.name || prompt.id }}</span>\n          <small>{{ prompt.id }}</small>\n        </button>\n      </aside>\n\n      <main v-if=\"selectedPrompt\" class=\"editor\">\n        <section class=\"panel\">\n          <h4>提示词编辑</h4>\n          <label class=\"field\">\n            <span>名称</span>\n            <input class=\"input\" :value=\"selectedPrompt.name\" type=\"text\" @input=\"updatePromptName($event)\" />\n          </label>\n          <label class=\"field\">\n            <span>ID</span>\n            <input class=\"input\" :value=\"selectedPrompt.id\" type=\"text\" @input=\"updatePromptId($event)\" />\n          </label>\n          <div class=\"row\">\n            <label class=\"field\">\n              <span>角色</span>\n              <select class=\"input\" :value=\"selectedPrompt.role\" @change=\"updatePromptRole($event)\">\n                <option value=\"system\">system</option>\n                <option value=\"user\">user</option>\n                <option value=\"assistant\">assistant</option>\n              </select>\n            </label>\n            <label class=\"field\">\n              <span>位置</span>\n              <select class=\"input\" :value=\"selectedPositionType\" @change=\"updatePromptPositionType($event)\">\n                <option value=\"relative\">relative</option>\n                <option value=\"in_chat\">in_chat</option>\n              </select>\n            </label>\n          </div>\n          <div v-if=\"selectedPositionType === 'in_chat'\" class=\"row\">\n            <label class=\"field\">\n              <span>深度</span>\n              <input\n                class=\"input\"\n                :value=\"selectedPrompt.position.type === 'in_chat' ? selectedPrompt.position.depth : 0\"\n                type=\"number\"\n                step=\"1\"\n                @input=\"updatePromptDepth($event)\"\n              />\n            </label>\n            <label class=\"field\">\n              <span>顺序</span>\n              <input\n                class=\"input\"\n                :value=\"selectedPrompt.position.type === 'in_chat' ? selectedPrompt.position.order : 0\"\n                type=\"number\"\n                step=\"1\"\n                @input=\"updatePromptOrder($event)\"\n              />\n            </label>\n          </div>\n          <label class=\"check\">\n            <input :checked=\"selectedPrompt.enabled\" type=\"checkbox\" @change=\"updatePromptEnabled($event)\" />\n            <span>启用此词条</span>\n          </label>\n          <label class=\"field\">\n            <span>内容</span>\n            <textarea class=\"input textarea\" :value=\"selectedPrompt.content ?? ''\" @input=\"updatePromptContent($event)\"></textarea>\n          </label>\n          <div class=\"ops\">\n            <button class=\"btn mini\" type=\"button\" @click=\"$emit('move-prompt', selectedPromptIndex, -1)\">上移</button>\n            <button class=\"btn mini\" type=\"button\" @click=\"$emit('move-prompt', selectedPromptIndex, 1)\">下移</button>\n            <button class=\"btn mini danger\" type=\"button\" @click=\"$emit('remove-prompt', selectedPromptIndex)\">删除</button>\n          </div>\n        </section>\n\n        <section class=\"panel\">\n          <h4>参数编辑（完整）</h4>\n          <details v-for=\"group in groups\" :key=\"group.id\" class=\"group\">\n            <summary>{{ group.title }}</summary>\n            <div class=\"fields\">\n              <label v-for=\"field in group.fields\" :key=\"String(field.key)\" class=\"field\">\n                <span>{{ field.label }}</span>\n                <input\n                  v-if=\"field.type === 'number'\"\n                  class=\"input\"\n                  type=\"number\"\n                  :value=\"toNumberInputValue(draftPreset.settings[field.key])\"\n                  :min=\"field.min\"\n                  :max=\"field.max\"\n                  :step=\"field.step ?? 1\"\n                  @input=\"updateSettingNumber(field.key, $event)\"\n                />\n                <select\n                  v-else-if=\"field.type === 'select'\"\n                  class=\"input\"\n                  :value=\"String(draftPreset.settings[field.key])\"\n                  @change=\"updateSettingSelect(field.key, $event)\"\n                >\n                  <option v-for=\"option in field.options\" :key=\"option.value\" :value=\"option.value\">\n                    {{ option.label }}\n                  </option>\n                </select>\n                <label v-else class=\"check\">\n                  <input\n                    :checked=\"Boolean(draftPreset.settings[field.key])\"\n                    type=\"checkbox\"\n                    @change=\"updateSettingBoolean(field.key, $event)\"\n                  />\n                  <span>{{ Boolean(draftPreset.settings[field.key]) ? '开启' : '关闭' }}</span>\n                </label>\n              </label>\n            </div>\n          </details>\n        </section>\n      </main>\n      <div v-else class=\"empty\">当前预设没有可编辑词条</div>\n    </div>\n\n    <div v-else class=\"empty\">请先选择预设</div>\n  </section>\n</template>\n\n<script setup lang=\"ts\">\nimport { computed } from 'vue';\n\nimport { clonePreset, presetSettingGroups } from '../core/presetMapper';\nimport type { EditApplyMode } from '../types';\n\nconst props = defineProps<{\n  draftPreset: Preset | null;\n  dirty: boolean;\n  applyMode: EditApplyMode;\n  selectedPromptIndex: number;\n  saving: boolean;\n}>();\n\nconst emit = defineEmits<{\n  save: [];\n  discard: [];\n  'append-prompt': [];\n  'remove-prompt': [index: number];\n  'move-prompt': [index: number, direction: -1 | 1];\n  'set-selected-prompt-index': [index: number];\n  'update-apply-mode': [mode: EditApplyMode];\n  'update-draft': [preset: Preset];\n}>();\n\nconst groups = presetSettingGroups;\n\nconst selectedPrompt = computed(() => {\n  if (!props.draftPreset) {\n    return null;\n  }\n  return props.draftPreset.prompts[props.selectedPromptIndex] ?? null;\n});\n\nconst selectedPositionType = computed(() => {\n  if (!selectedPrompt.value) {\n    return 'relative';\n  }\n  return selectedPrompt.value.position.type;\n});\n\nfunction emitApplyMode(modeRaw: string): void {\n  const mode: EditApplyMode = modeRaw === 'draft' ? 'draft' : 'live';\n  emit('update-apply-mode', mode);\n}\n\nfunction mutateDraft(mutator: (draft: Preset) => void): void {\n  if (!props.draftPreset) {\n    return;\n  }\n  const draft = clonePreset(props.draftPreset);\n  mutator(draft);\n  emit('update-draft', draft);\n}\n\nfunction toNumberInputValue(value: unknown): string {\n  if (typeof value === 'number' && Number.isFinite(value)) {\n    return String(value);\n  }\n  return '';\n}\n\nfunction updatePromptName(event: Event): void {\n  const value = (event.target as HTMLInputElement).value;\n  mutateDraft(draft => {\n    const prompt = draft.prompts[props.selectedPromptIndex];\n    if (prompt) {\n      prompt.name = value;\n    }\n  });\n}\n\nfunction updatePromptId(event: Event): void {\n  const value = (event.target as HTMLInputElement).value;\n  mutateDraft(draft => {\n    const prompt = draft.prompts[props.selectedPromptIndex];\n    if (prompt) {\n      prompt.id = value;\n    }\n  });\n}\n\nfunction updatePromptRole(event: Event): void {\n  const value = (event.target as HTMLSelectElement).value as PresetPrompt['role'];\n  mutateDraft(draft => {\n    const prompt = draft.prompts[props.selectedPromptIndex];\n    if (prompt) {\n      prompt.role = value;\n    }\n  });\n}\n\nfunction updatePromptPositionType(event: Event): void {\n  const value = (event.target as HTMLSelectElement).value;\n  mutateDraft(draft => {\n    const prompt = draft.prompts[props.selectedPromptIndex];\n    if (!prompt) {\n      return;\n    }\n    if (value === 'in_chat') {\n      prompt.position = { type: 'in_chat', depth: 4, order: 100 };\n      return;\n    }\n    prompt.position = { type: 'relative' };\n  });\n}\n\nfunction updatePromptDepth(event: Event): void {\n  const value = Number((event.target as HTMLInputElement).value);\n  if (Number.isNaN(value)) {\n    return;\n  }\n  mutateDraft(draft => {\n    const prompt = draft.prompts[props.selectedPromptIndex];\n    if (prompt?.position.type === 'in_chat') {\n      prompt.position.depth = Math.max(0, Math.floor(value));\n    }\n  });\n}\n\nfunction updatePromptOrder(event: Event): void {\n  const value = Number((event.target as HTMLInputElement).value);\n  if (Number.isNaN(value)) {\n    return;\n  }\n  mutateDraft(draft => {\n    const prompt = draft.prompts[props.selectedPromptIndex];\n    if (prompt?.position.type === 'in_chat') {\n      prompt.position.order = Math.floor(value);\n    }\n  });\n}\n\nfunction updatePromptEnabled(event: Event): void {\n  const value = (event.target as HTMLInputElement).checked;\n  mutateDraft(draft => {\n    const prompt = draft.prompts[props.selectedPromptIndex];\n    if (prompt) {\n      prompt.enabled = value;\n    }\n  });\n}\n\nfunction updatePromptContent(event: Event): void {\n  const value = (event.target as HTMLTextAreaElement).value;\n  mutateDraft(draft => {\n    const prompt = draft.prompts[props.selectedPromptIndex];\n    if (prompt) {\n      prompt.content = value;\n    }\n  });\n}\n\nfunction updateSettingNumber(key: keyof Preset['settings'], event: Event): void {\n  const value = Number((event.target as HTMLInputElement).value);\n  if (Number.isNaN(value)) {\n    return;\n  }\n  mutateDraft(draft => {\n    draft.settings[key] = value as Preset['settings'][keyof Preset['settings']];\n  });\n}\n\nfunction updateSettingSelect(key: keyof Preset['settings'], event: Event): void {\n  const value = (event.target as HTMLSelectElement).value;\n  mutateDraft(draft => {\n    draft.settings[key] = value as Preset['settings'][keyof Preset['settings']];\n  });\n}\n\nfunction updateSettingBoolean(key: keyof Preset['settings'], event: Event): void {\n  const value = (event.target as HTMLInputElement).checked;\n  mutateDraft(draft => {\n    draft.settings[key] = value as Preset['settings'][keyof Preset['settings']];\n  });\n}\n</script>\n\n<style scoped>\n.edit-shell {\n  border: 1px solid rgba(70, 93, 122, 0.7);\n  border-radius: 12px;\n  overflow: hidden;\n  background: linear-gradient(160deg, rgba(17, 24, 39, 0.88), rgba(9, 14, 26, 0.95));\n  display: flex;\n  flex-direction: column;\n  min-height: 0;\n}\n\n.toolbar {\n  display: flex;\n  justify-content: space-between;\n  gap: 10px;\n  align-items: center;\n  padding: 10px 12px;\n  border-bottom: 1px solid rgba(70, 93, 122, 0.65);\n  flex-wrap: wrap;\n}\n\n.mode {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  color: #bfd4f2;\n  font-size: 12px;\n}\n\n.select,\n.input,\n.textarea {\n  border: 1px solid rgba(78, 105, 140, 0.72);\n  border-radius: 7px;\n  background: rgba(15, 23, 42, 0.9);\n  color: #f8fbff;\n  padding: 5px 8px;\n}\n\n.actions {\n  display: inline-flex;\n  gap: 8px;\n}\n\n.content {\n  min-height: 0;\n  flex: 1;\n  display: grid;\n  grid-template-columns: 280px minmax(0, 1fr);\n}\n\n.prompt-list {\n  border-right: 1px solid rgba(70, 93, 122, 0.65);\n  padding: 10px;\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n  overflow: auto;\n}\n\n.prompt-list-head {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  color: #bfd4f2;\n}\n\n.prompt-item {\n  border: 1px solid rgba(62, 84, 114, 0.8);\n  border-radius: 8px;\n  background: rgba(15, 23, 42, 0.82);\n  color: #e8f2ff;\n  text-align: left;\n  padding: 7px 8px;\n  display: grid;\n  gap: 2px;\n  cursor: pointer;\n}\n\n.prompt-item small {\n  color: #8fb2df;\n  font-size: 11px;\n}\n\n.prompt-item.active {\n  border-color: #60a5fa;\n  box-shadow: 0 0 0 1px rgba(96, 165, 250, 0.32) inset;\n}\n\n.editor {\n  min-height: 0;\n  overflow: auto;\n  padding: 10px;\n  display: grid;\n  gap: 12px;\n}\n\n.panel {\n  border: 1px solid rgba(62, 84, 114, 0.8);\n  border-radius: 9px;\n  padding: 9px;\n  background: rgba(15, 23, 42, 0.75);\n  display: grid;\n  gap: 8px;\n}\n\n.panel h4 {\n  margin: 0;\n  color: #dbeafe;\n  font-size: 13px;\n}\n\n.field {\n  display: grid;\n  gap: 4px;\n}\n\n.field > span {\n  color: #b8d2f5;\n  font-size: 12px;\n}\n\n.row {\n  display: grid;\n  grid-template-columns: 1fr 1fr;\n  gap: 8px;\n}\n\n.textarea {\n  min-height: 140px;\n}\n\n.check {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  color: #f4f8ff;\n  font-size: 12px;\n}\n\n.ops {\n  display: inline-flex;\n  gap: 8px;\n  flex-wrap: wrap;\n}\n\n.group {\n  border: 1px solid rgba(57, 79, 110, 0.62);\n  border-radius: 8px;\n  background: rgba(15, 23, 42, 0.68);\n}\n\n.group > summary {\n  cursor: pointer;\n  list-style: none;\n  padding: 8px 10px;\n  color: #dbeafe;\n  font-size: 12px;\n}\n\n.group .fields {\n  display: grid;\n  gap: 8px;\n  padding: 8px;\n}\n\n.btn {\n  border: 1px solid rgba(91, 123, 175, 0.62);\n  border-radius: 8px;\n  background: #1f2a44;\n  color: #f5f8ff;\n  padding: 6px 12px;\n  cursor: pointer;\n}\n\n.btn.primary {\n  background: #1e5ab8;\n  border-color: #3b82f6;\n}\n\n.btn.danger {\n  background: #42212a;\n  border-color: #fb7185;\n}\n\n.btn.mini {\n  padding: 4px 10px;\n  font-size: 12px;\n}\n\n.btn:disabled {\n  opacity: 0.5;\n  cursor: default;\n}\n\n.empty {\n  padding: 16px;\n  color: #8ba3c7;\n  font-size: 12px;\n}\n\n@media (max-width: 1100px) {\n  .content {\n    grid-template-columns: 1fr;\n  }\n\n  .prompt-list {\n    border-right: none;\n    border-bottom: 1px solid rgba(70, 93, 122, 0.65);\n    max-height: 220px;\n  }\n\n  .row {\n    grid-template-columns: 1fr;\n  }\n}\n</style>\n"],"sourceRoot":""}]);
