\n}\n\n.switch {\n  position: relative;\n  display: inline-block;\n  width: 44px;\n  height: 24px;\n}\n\n.switch input {\n  opacity: 0;\n  width: 0;\n  height: 0;\n}\n\n.slider {\n  position: absolute;\n  inset: 0;\n  border-radius: 999px;\n  background: rgba(88, 108, 140, 0.6);\n  transition: 0.18s;\n}\n\n.slider::before {\n  content: '';\n  position: absolute;\n  width: 18px;\n  height: 18px;\n  left: 3px;\n  top: 3px;\n  border-radius: 50%;\n  background: #f8fbff;\n  transition: 0.18s;\n}\n\ninput:checked + .slider {\n  background: #1d4ed8;\n}\n\ninput:checked + .slider::before {\n  transform: translateX(20px);\n}\n\n.empty {\n  padding: 14px;\n  color: #8ba3c7;\n  font-size: 12px;\n}\n</style>\n"],"sourceRoot":""}]);
