`, "",{"version":3,"sources":["webpack://./src/presets_assistant_build/components/BrowseSettingsPanel.vue"],"names":[],"mappings":"AAsIA,iCACE,oCAAwC,CACxC,kBAAmB,CACnB,wEAAiF,CACjF,YAAa,CACb,qBAAsB,CACtB,YACF,CAEA,uBACE,iBAAkB,CAClB,4CAAgD,CAChD,YAAa,CACb,6BAA8B,CAC9B,kBACF,CAEA,0BACE,QAAS,CACT,cAAe,CACf,aACF,CAEA,kCACE,mBAAoB,CACpB,OAAQ,CACR,kBAAmB,CACnB,aAAc,CACd,cACF,CAEA,yBACE,aAAc,CACd,gBAAiB,CACjB,WAAY,CACZ,YAAa,CACb,OACF,CAEA,wBACE,qCAAyC,CACzC,iBAAkB,CAClB,8BACF,CAEA,gCACE,cAAe,CACf,eAAgB,CAChB,gBAAiB,CACjB,aAAc,CACd,cAAe,CACf,2CACF,CAEA,yBACE,YAAa,CACb,OAAQ,CACR,WACF,CAEA,wBACE,YAAa,CACb,OACF,CAEA,6BACE,mBAAoB,CACpB,OAAQ,CACR,kBAAmB,CACnB,aAAc,CACd,cACF,CAEA,+BACE,iBAAkB,CAClB,aAAc,CACd,cACF,CAEA,wBACE,sCAA0C,CAC1C,iBAAkB,CAClB,6BAAiC,CACjC,aAAc,CACd,eAAgB,CAChB,eACF,CAEA,wBACE,mBAAoB,CACpB,kBAAmB,CACnB,OAAQ,CACR,aAAc,CACd,cACF,CAEA,0BACE,eAAgB,CAChB,QAAS,CACT,YAAa,CACb,wBAAyB,CACzB,OAAQ,CACR,iBAAkB,CAClB,yCAA6C,CAC7C,4BAAgC,CAChC,yBACF,CAEA,sBACE,sCAA0C,CAC1C,iBAAkB,CAClB,kBAAmB,CACnB,aAAc,CACd,gBAAiB,CACjB,cACF,CAEA,8BACE,kBAAmB,CACnB,oBACF,CAEA,+BACE,WAAY,CACZ,cACF","sourcesContent":["<template>\n  <section class=\"settings-panel\">\n    <div class=\"head\">\n      <h3>生成参数（浏览态）</h3>\n      <label class=\"collapse-toggle\">\n        <input :checked=\"open\" type=\"checkbox\" @change=\"$emit('toggle-open', ($event.target as HTMLInputElement).checked)\" />\n        <span>展开</span>\n      </label>\n    </div>\n\n    <div v-if=\"open\" class=\"groups\">\n      <details\n        v-for=\"group in groups\"\n        :key=\"group.id\"\n        :open=\"group.id === expandedGroup\"\n        class=\"group\"\n        @toggle=\"onGroupToggle(group.id, $event)\"\n      >\n        <summary>{{ group.title }}</summary>\n        <div class=\"fields\">\n          <label v-for=\"field in group.fields\" :key=\"String(field.key)\" class=\"field\">\n            <span>\n              {{ field.label }}\n              <i v-if=\"isFieldChanged(field)\">已改</i>\n            </span>\n\n            <input\n              v-if=\"field.type === 'number'\"\n              :value=\"toNumberInputValue(stagedSettings[field.key])\"\n              type=\"number\"\n              class=\"input\"\n              :min=\"field.min\"\n              :max=\"field.max\"\n              :step=\"field.step ?? 1\"\n              @input=\"onNumberInput(field, $event)\"\n            />\n\n            <select\n              v-else-if=\"field.type === 'select'\"\n              class=\"input\"\n              :value=\"String(stagedSettings[field.key])\"\n              @change=\"onSelectInput(field, $event)\"\n            >\n              <option v-for=\"option in field.options\" :key=\"option.value\" :value=\"option.value\">\n                {{ option.label }}\n              </option>\n            </select>\n\n            <label v-else class=\"check\">\n              <input\n                :checked=\"Boolean(stagedSettings[field.key])\"\n                type=\"checkbox\"\n                @change=\"onBooleanInput(field, $event)\"\n              />\n              <span>{{ Boolean(stagedSettings[field.key]) ? '开启' : '关闭' }}</span>\n            </label>\n          </label>\n        </div>\n      </details>\n    </div>\n\n    <div v-if=\"open\" class=\"actions\">\n      <button class=\"btn\" type=\"button\" :disabled=\"!dirty || applying\" @click=\"$emit('reset')\">重置</button>\n      <button class=\"btn primary\" type=\"button\" :disabled=\"!dirty || applying\" @click=\"$emit('apply')\">\n        {{ applying ? '应用中...' : '应用' }}\n      </button>\n    </div>\n  </section>\n</template>\n\n<script setup lang=\"ts\">\nimport _ from 'lodash';\n\nimport { presetSettingGroups } from '../core/presetMapper';\nimport type { SettingField } from '../types';\n\nconst props = defineProps<{\n  stagedSettings: Preset['settings'];\n  baseSettings: Preset['settings'];\n  dirty: boolean;\n  applying: boolean;\n  open: boolean;\n  expandedGroup: string;\n}>();\n\nconst emit = defineEmits<{\n  apply: [];\n  reset: [];\n  'toggle-open': [open: boolean];\n  'set-expanded-group': [groupId: string];\n  'update-setting': [key: keyof Preset['settings'], value: Preset['settings'][keyof Preset['settings']]];\n}>();\n\nconst groups = presetSettingGroups;\n\nfunction isFieldChanged(field: SettingField): boolean {\n  return !_.isEqual(props.baseSettings[field.key], props.stagedSettings[field.key]);\n}\n\nfunction toNumberInputValue(value: unknown): string {\n  if (typeof value === 'number' && Number.isFinite(value)) {\n    return String(value);\n  }\n  return '';\n}\n\nfunction onGroupToggle(groupId: string, event: Event): void {\n  const target = event.target as HTMLDetailsElement;\n  if (target.open) {\n    emit('set-expanded-group', groupId);\n  }\n}\n\nfunction onNumberInput(field: SettingField, event: Event): void {\n  const target = event.target as HTMLInputElement;\n  const next = Number(target.value);\n  if (Number.isNaN(next)) {\n    return;\n  }\n  emit('update-setting', field.key, next as Preset['settings'][keyof Preset['settings']]);\n}\n\nfunction onSelectInput(field: SettingField, event: Event): void {\n  const target = event.target as HTMLSelectElement;\n  emit('update-setting', field.key, target.value as Preset['settings'][keyof Preset['settings']]);\n}\n\nfunction onBooleanInput(field: SettingField, event: Event): void {\n  const target = event.target as HTMLInputElement;\n  emit('update-setting', field.key, target.checked as Preset['settings'][keyof Preset['settings']]);\n}\n</script>\n\n<style scoped>\n.settings-panel {\n  border: 1px solid rgba(70, 93, 122, 0.7);\n  border-radius: 12px;\n  background: linear-gradient(145deg, rgba(17, 24, 39, 0.9), rgba(8, 13, 24, 0.95));\n  display: flex;\n  flex-direction: column;\n  min-height: 0;\n}\n\n.head {\n  padding: 10px 12px;\n  border-bottom: 1px solid rgba(70, 93, 122, 0.65);\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n}\n\n.head h3 {\n  margin: 0;\n  font-size: 14px;\n  color: #f8fbff;\n}\n\n.collapse-toggle {\n  display: inline-flex;\n  gap: 6px;\n  align-items: center;\n  color: #a8c6f0;\n  font-size: 12px;\n}\n\n.groups {\n  overflow: auto;\n  max-height: 420px;\n  padding: 8px;\n  display: grid;\n  gap: 8px;\n}\n\n.group {\n  border: 1px solid rgba(57, 79, 110, 0.62);\n  border-radius: 8px;\n  background: rgba(15, 23, 42, 0.68);\n}\n\n.group > summary {\n  cursor: pointer;\n  list-style: none;\n  padding: 8px 10px;\n  color: #dbeafe;\n  font-size: 13px;\n  border-bottom: 1px solid rgba(57, 79, 110, 0.5);\n}\n\n.fields {\n  display: grid;\n  gap: 8px;\n  padding: 9px;\n}\n\n.field {\n  display: grid;\n  gap: 4px;\n}\n\n.field > span {\n  display: inline-flex;\n  gap: 8px;\n  align-items: center;\n  color: #b8d2f5;\n  font-size: 12px;\n}\n\n.field > span i {\n  font-style: normal;\n  color: #fbbf24;\n  font-size: 11px;\n}\n\n.input {\n  border: 1px solid rgba(78, 105, 140, 0.72);\n  border-radius: 7px;\n  background: rgba(15, 23, 42, 0.9);\n  color: #f8fbff;\n  padding: 5px 8px;\n  min-height: 32px;\n}\n\n.check {\n  display: inline-flex;\n  align-items: center;\n  gap: 8px;\n  color: #f4f8ff;\n  font-size: 12px;\n}\n\n.actions {\n  position: sticky;\n  bottom: 0;\n  display: flex;\n  justify-content: flex-end;\n  gap: 8px;\n  padding: 10px 12px;\n  border-top: 1px solid rgba(70, 93, 122, 0.65);\n  background: rgba(6, 10, 20, 0.9);\n  backdrop-filter: blur(6px);\n}\n\n.btn {\n  border: 1px solid rgba(91, 123, 175, 0.62);\n  border-radius: 8px;\n  background: #1f2a44;\n  color: #f5f8ff;\n  padding: 6px 12px;\n  cursor: pointer;\n}\n\n.btn.primary {\n  background: #1e5ab8;\n  border-color: #3b82f6;\n}\n\n.btn:disabled {\n  opacity: 0.5;\n  cursor: default;\n}\n</style>\n"],"sourceRoot":""}]);
